DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$x = list_random('a'..'n', 'p'..'z', 'A'..'D', 'F'..'N', 'P'..'T', 'V'..'Z');
Context()->variables->are($x => 'Real');
$sol = non_zero_random(-9, 9);
$m = list_random(-9..-2, 2..9);
$b = non_zero_random(-9, 9);
$c = $m*$sol + $b;
Context()->noreduce('(-x)-y', '(-x)+y');
$left = Formula("$m $x + $b")->reduce;
$right = Formula("$c")->reduce;
Context("FiniteSolutionSets");
Context()->variables->are($x => 'Real');
$solset = Formula("{$sol}");
$solleft[0]  = Formula("$m $x + $b - $b")->reduce;
$solright[0] = Formula("$x - $b")->reduce;
$solright[0] = $solright[0]->substitute($x => $c);
$solleft[1]  = Formula("$m $x")->reduce;
$solright[1] = Formula("$c - $b")->reduce;
Context("Fraction")->flags->set(reduceFractions => 0);
Context()->variables->are($x => 'Real');
Context()->noreduce('x/(-y)', '(-x)/y');
$solleft[2]  = Formula("($m $x)/$m")->reduce;
$solright[2] = $solright[1]/Formula("$m");
$solleft[3]  = Formula("$x");
$solright[3] = Formula("$sol");

############################################################
# Body
############################################################

BEGIN_PGML
Solve the equation.

[`[$left]=[$right]`]

[_]{$solset}{16}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION

[```\newcommand{\amp}{&}
\begin{aligned}
 [$left] \amp= [$right] \\
 [$solleft[0]] \amp= [$solright[0]] \\
 [$solleft[1]] \amp= [$solright[1]] \\
 [$solleft[2]] \amp= [$solright[2]] \\
 [$solleft[3]] \amp= [$solright[3]] 
\end{aligned}
```]

The solution set is [`[$solset]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
